import{_ as e,o as a,c as n,a2 as t}from"./chunks/framework.DdLJaIXX.js";const u=JSON.parse('{"title":"Knowledge Loop","description":"","frontmatter":{},"headers":[],"relativePath":"guide/growth-loop.md","filePath":"guide/growth-loop.md"}'),i={name:"guide/growth-loop.md"};function p(o,s,l,r,h,c){return a(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="knowledge-loop" tabindex="-1">Knowledge Loop <a class="header-anchor" href="#knowledge-loop" aria-label="Permalink to &quot;Knowledge Loop&quot;">​</a></h1><blockquote><p>Connect, Adapt, Evolve — every AI session feeds the next.</p></blockquote><p>Every time you work with an AI, you teach it something. Usually that knowledge disappears when the session ends. The Knowledge Loop captures it, accumulates it, and injects it back — so each session starts smarter than the last.</p><hr><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>AI sessions start from zero. You explain your conventions, correct the same mistakes, re-state the same constraints — every time. By session 100, you&#39;ve spent hours re-teaching what the AI already learned and forgot.</p><p>The Knowledge Loop closes that loop permanently.</p><hr><h2 id="what-is-the-knowledge-loop" tabindex="-1">What Is the Knowledge Loop? <a class="header-anchor" href="#what-is-the-knowledge-loop" aria-label="Permalink to &quot;What Is the Knowledge Loop?&quot;">​</a></h2><p>A three-stage pipeline that runs automatically every time a session ends:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You work with AI</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>Session ends → CQ extracts what was learned</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>Knowledge record → count increments in PreferenceLedger</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ├── count ≥ 3 → hint added to CLAUDE.md (soft guidance)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       └── count ≥ 5 → promoted to rule in .claude/rules/ (permanent behavior)</span></span>
<span class="line"><span>                               │</span></span>
<span class="line"><span>                               ▼</span></span>
<span class="line"><span>                    Next session: AI already knows this</span></span></code></pre></div><p>No configuration required. No tagging. CQ observes and extracts automatically.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><h3 id="stage-1-session-→-knowledge-record" tabindex="-1">Stage 1: Session → Knowledge Record <a class="header-anchor" href="#stage-1-session-→-knowledge-record" aria-label="Permalink to &quot;Stage 1: Session → Knowledge Record&quot;">​</a></h3><p>When a session closes, CQ analyzes what happened:</p><ul><li>Corrections you made to AI output (&quot;not like that, do it this way&quot;)</li><li>Patterns in commands you ran repeatedly</li><li>Explicit instructions you gave during the session</li><li>Experiment results and which approaches worked</li></ul><p>Each observation becomes a knowledge record with a type and content:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> knowledge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;test patterns&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → &quot;prefer table-driven tests in Go, name subtests descriptively&quot; (session 2026-03-28)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># → &quot;use t.Run() for subtests, not nested test functions&quot; (session 2026-03-22)</span></span></code></pre></div><h3 id="stage-2-knowledge-record-→-preference-ledger" tabindex="-1">Stage 2: Knowledge Record → Preference Ledger <a class="header-anchor" href="#stage-2-knowledge-record-→-preference-ledger" aria-label="Permalink to &quot;Stage 2: Knowledge Record → Preference Ledger&quot;">​</a></h3><p>Related records accumulate in the PreferenceLedger. Each time the same pattern appears, its count increments:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ID       Count  Level  Preference</span></span>
<span class="line"><span>pref-01  7      RULE   Use table-driven tests in Go</span></span>
<span class="line"><span>pref-02  5      RULE   Run go vet before committing</span></span>
<span class="line"><span>pref-03  4      HINT   Check MPJPE/HD/MSD metrics in that order</span></span>
<span class="line"><span>pref-04  2      -      Sort imports before committing</span></span></code></pre></div><h3 id="stage-3-next-session-context-injection" tabindex="-1">Stage 3: Next Session Context Injection <a class="header-anchor" href="#stage-3-next-session-context-injection" aria-label="Permalink to &quot;Stage 3: Next Session Context Injection&quot;">​</a></h3><p>Before each session starts, CQ injects relevant knowledge into the AI&#39;s context:</p><ul><li><strong>Rules</strong> (count ≥ 5): Written to <code>.claude/rules/</code> — loaded into every system prompt</li><li><strong>Hints</strong> (count ≥ 3): Added to <code>CLAUDE.md</code> — soft suggestions the AI sees</li></ul><p>The AI doesn&#39;t need to be told. It already knows.</p><hr><h2 id="cross-platform-claude-discovers-chatgpt-uses-it" tabindex="-1">Cross-Platform: Claude Discovers, ChatGPT Uses It <a class="header-anchor" href="#cross-platform-claude-discovers-chatgpt-uses-it" aria-label="Permalink to &quot;Cross-Platform: Claude Discovers, ChatGPT Uses It&quot;">​</a></h2><p>In <strong>Pro</strong> and <strong>Team</strong> tiers, the PreferenceLedger lives in the cloud, not on your machine.</p><p>A preference observed in a Claude Code session is available in your ChatGPT session the next day. A pattern learned in Cursor shows up in Claude Desktop. Your AI knowledge is unified across tools.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Monday: You correct Claude Code three times about a pattern.</span></span>
<span class="line"><span>        → pref-07 count: 3 → hint created</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Tuesday: You open ChatGPT.</span></span>
<span class="line"><span>         → CQ injects pref-07 hint into ChatGPT&#39;s MCP context</span></span>
<span class="line"><span>         → ChatGPT already knows the pattern. No correction needed.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Friday: pref-07 count reaches 5.</span></span>
<span class="line"><span>        → Promoted to rule in .claude/rules/</span></span>
<span class="line"><span>        → All AI tools now treat this as a permanent constraint.</span></span></code></pre></div><p>No export, no import, no manual sync. The Knowledge Loop handles it.</p><hr><h2 id="persona-ai-learns-to-code-like-you" tabindex="-1">Persona: AI Learns to Code Like You <a class="header-anchor" href="#persona-ai-learns-to-code-like-you" aria-label="Permalink to &quot;Persona: AI Learns to Code Like You&quot;">​</a></h2><p>Over time, the Knowledge Loop builds a model of your preferences across every dimension of how you work:</p><ul><li>Code style (naming conventions, error handling patterns, test structure)</li><li>Review criteria (what you approve, what you reject, why)</li><li>Experiment methodology (which metrics matter, how you evaluate results)</li><li>Communication style (how detailed you want explanations, what you skip)</li></ul><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rules</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ID       Count  Preference</span></span>
<span class="line"><span>pref-01  12     Always use context.Context as first parameter</span></span>
<span class="line"><span>pref-02  9      Return errors, don&#39;t log and return</span></span>
<span class="line"><span>pref-03  7      Table-driven tests with descriptive subtest names</span></span>
<span class="line"><span>pref-04  6      Check MPJPE before HD before MSD in pose estimation</span></span>
<span class="line"><span>pref-05  5      Commit messages: imperative mood, 50 char subject limit</span></span></code></pre></div><p>These rules load into every AI session automatically. The AI doesn&#39;t just follow instructions — it has internalized your judgment.</p><hr><h2 id="team-teammate-s-discovery-becomes-your-context" tabindex="-1">Team: Teammate&#39;s Discovery Becomes Your Context <a class="header-anchor" href="#team-teammate-s-discovery-becomes-your-context" aria-label="Permalink to &quot;Team: Teammate&#39;s Discovery Becomes Your Context&quot;">​</a></h2><p>In <strong>Team</strong> tier, the Knowledge Loop extends across your team.</p><p>When Alice&#39;s AI discovers that &quot;gradient norm &gt; 10 before epoch 5 predicts training instability&quot;, that pattern — after it&#39;s confirmed through multiple sessions — propagates to your AI&#39;s context automatically.</p><p>You skip the trial-and-error Alice already paid for.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Alice&#39;s sessions (week 1):</span></span>
<span class="line"><span>  → Discovers: gradient norm check pattern</span></span>
<span class="line"><span>  → count reaches 5 → team rule created</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Your session (week 2):</span></span>
<span class="line"><span>  → CQ injects Alice&#39;s rule into your context</span></span>
<span class="line"><span>  → &quot;Check gradient norms before epoch 5&quot;</span></span>
<span class="line"><span>  → You never ran into the instability Alice debugged</span></span></code></pre></div><p>What gets shared: behavioral patterns, workflow sequences, tool preferences. What never gets shared: file paths, repo names, email addresses, personal identifiers.</p><hr><h2 id="a-concrete-example-day-1-vs-day-30" tabindex="-1">A Concrete Example: Day 1 vs Day 30 <a class="header-anchor" href="#a-concrete-example-day-1-vs-day-30" aria-label="Permalink to &quot;A Concrete Example: Day 1 vs Day 30&quot;">​</a></h2><p><strong>Day 1 — AI doesn&#39;t know you:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You: &quot;Write a test for this function&quot;</span></span>
<span class="line"><span>AI: func TestFoo(t *testing.T) {</span></span>
<span class="line"><span>      result := Foo(input)</span></span>
<span class="line"><span>      if result != expected {</span></span>
<span class="line"><span>        t.Errorf(&quot;...&quot;)</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You: &quot;Use table-driven tests. And use t.Run for subtests.&quot;</span></span>
<span class="line"><span>AI: [rewrites with table-driven pattern]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>You: &quot;The subtest names should be descriptive, not &#39;case 1&#39;&quot;</span></span>
<span class="line"><span>AI: [rewrites again]</span></span></code></pre></div><p>Three corrections. Fifteen minutes of back-and-forth.</p><p><strong>Day 30 — AI codes like you:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You: &quot;Write a test for this function&quot;</span></span>
<span class="line"><span>AI: func TestFoo(t *testing.T) {</span></span>
<span class="line"><span>      tests := []struct{</span></span>
<span class="line"><span>        name   string</span></span>
<span class="line"><span>        input  string</span></span>
<span class="line"><span>        expect string</span></span>
<span class="line"><span>      }{</span></span>
<span class="line"><span>        {name: &quot;empty input returns error&quot;, ...},</span></span>
<span class="line"><span>        {name: &quot;valid input returns processed result&quot;, ...},</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>      for _, tc := range tests {</span></span>
<span class="line"><span>        t.Run(tc.name, func(t *testing.T) { ... })</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    }</span></span></code></pre></div><p>Zero corrections. The AI already knows your style.</p><hr><h2 id="managing-your-knowledge" tabindex="-1">Managing Your Knowledge <a class="header-anchor" href="#managing-your-knowledge" aria-label="Permalink to &quot;Managing Your Knowledge&quot;">​</a></h2><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # All preferences with counts</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hints</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Only hints (count ≥ 3)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rules</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # Only rules (count ≥ 5)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> preferences</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">i</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # Detail for one preference</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rule</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;check mpjpe first&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Delete + permanently suppress</span></span></code></pre></div><p>Deleting a rule suppresses it permanently — CQ will never re-promote that pattern.</p><hr><h2 id="tier-scope" tabindex="-1">Tier Scope <a class="header-anchor" href="#tier-scope" aria-label="Permalink to &quot;Tier Scope&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tier</th><th>Knowledge scope</th></tr></thead><tbody><tr><td>Free</td><td>Single project, local SQLite</td></tr><tr><td>Pro</td><td>All your projects + all your AI tools, cloud-synced</td></tr><tr><td>Team</td><td>Everything in Pro + teammates&#39; discoveries</td></tr></tbody></table><hr><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>The Knowledge Loop runs automatically. To disable:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># .c4/config.yaml</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">growth_loop</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>To trigger manually after a session:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> close</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # Triggers summary + preference extraction</span></span></code></pre></div>`,68)])])}const g=e(i,[["render",p]]);export{u as __pageData,g as default};
